#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *A = (int*)malloc((N+1)*sizeof(int));
        int *pos = (int*)malloc((N+1)*sizeof(int));
        for(int i=1;i<=N;i++){
            scanf("%d",&A[i]);
            pos[A[i]] = i;
        }
        int minPos = pos[N];
        int maxPos = pos[N];
        int best = 1; // k=1 always valid because N is present
        for(int k=2;k<N;k++){
            int val = N - k + 1; // new value to include
            if(pos[val] < minPos) minPos = pos[val];
            if(pos[val] > maxPos) maxPos = pos[val];
            if(maxPos - minPos + 1 == k) best = k;
        }
        printf("%d\n",best);
        free(A); free(pos);
    }
    return 0;
}

